  1	import * as React from 'react';
  2	import {
  3	  Form,
  4	  FormGroup,
  5	  FormHelperText,
  6	  HelperText,
  7	  HelperTextItem,
  8	  MenuToggle,
  9	  Radio,
 10	  Select,
 11	  SelectList,
 12	  SelectOption,
 13	  Switch,
 14	  TextInput
 15	} from '@patternfly/react-core';
 16	import { GATEWAY_TOOLTIP, wizardTooltip } from './WizardHelp';
 17	import { isValid } from 'utils/Common';
 18	import { isK8sGatewayHostValid } from '../../utils/IstioConfigUtils';
 19	import { serverConfig } from '../../config';
 20	
 21	type Props = {
 22	  gateway: string;
 23	  hasGateway: boolean;
 24	  k8sGateways: string[];
 25	  k8sRouteHosts: string[];
 26	  onGatewayChange: (valid: boolean, gateway: K8sGatewaySelectorState) => void;
 27	  serviceName: string;
 28	};
 29	
 30	export type K8sGatewaySelectorState = {
 31	  addGateway: boolean;
 32	  // @TODO add Mesh is not supported yet
 33	  addMesh: boolean;
 34	  gatewayClass: string;
 35	  gwHosts: string;
 36	  gwHostsValid: boolean;
 37	  isOpen: boolean;
 38	  newGateway: boolean;
 39	  port: number;
 40	  selectedGateway: string;
 41	};
 42	
 43	enum K8sGatewayForm {
 44	  SWITCH,
 45	  GW_HOSTS,
 46	  SELECT,
 47	  GATEWAY_SELECTED,
 48	  PORT
 49	}
 50	
 51	export class K8sGatewaySelector extends React.Component<Props, K8sGatewaySelectorState> {
 52	  constructor(props: Props) {
 53	    super(props);
 54	    this.state = {
 55	      addGateway: props.hasGateway,
 56	      gwHosts: props.k8sRouteHosts.join(','),
 57	      gwHostsValid: true,
 58	      newGateway: props.k8sGateways.length === 0,
 59	      selectedGateway:
 60	        props.k8sGateways.length > 0 ? (props.gateway !== '' ? props.gateway : props.k8sGateways[0]) : '',
 61	      gatewayClass: serverConfig?.gatewayAPIClasses?.length > 0 ? serverConfig.gatewayAPIClasses[0].className : '',
 62	      addMesh: false,
 63	      port: 80,
 64	      isOpen: false
 65	    };
 66	  }
 67	
 68	  onToggleClick = (): void => {
 69	    this.setState(prevState => ({ isOpen: !prevState.isOpen }));
 70	  };
 71	
 72	  toggleMenu = (toggleRef: React.Ref<any>, label: string, isDisabled = false): React.ReactNode => (
 73	    <MenuToggle ref={toggleRef} onClick={this.onToggleClick} isExpanded={this.state.isOpen} isDisabled={isDisabled}>
 74	      {label}
 75	    </MenuToggle>
 76	  );
 77	
 78	  checkGwHosts = (gwHosts: string): boolean => {
 79	    // All k8s gateway hosts must be valid
 80	    return gwHosts.split(',').every(host => {
 81	      return isK8sGatewayHostValid(host);
 82	    });
 83	  };
 84	
 85	  onFormChange = (component: K8sGatewayForm, value: string): void => {
 86	    switch (component) {
 87	      case K8sGatewayForm.SWITCH:
 88	        this.setState(
 89	          prevState => {
 90	            return {
 91	              addGateway: !prevState.addGateway
 92	            };
 93	          },
 94	          () => this.props.onGatewayChange(this.isGatewayValid(), this.state)
 95	        );
 96	        break;
 97	      case K8sGatewayForm.GW_HOSTS:
 98	        this.setState(
 99	          {
100	            gwHosts: value,
101	            gwHostsValid: this.checkGwHosts(value)
102	          },
103	          () => this.props.onGatewayChange(this.isGatewayValid(), this.state)
104	        );
105	        break;
106	      case K8sGatewayForm.SELECT:
107	        this.setState(
108	          {
109	            newGateway: value === 'true'
110	          },
111	          () => this.props.onGatewayChange(this.isGatewayValid(), this.state)
112	        );
113	        break;
114	      case K8sGatewayForm.GATEWAY_SELECTED:
115	        this.setState(
116	          {
117	            selectedGateway: value,
118	            isOpen: false
119	          },
120	          () => this.props.onGatewayChange(this.isGatewayValid(), this.state)
121	        );
122	        break;
123	      case K8sGatewayForm.PORT:
124	        this.setState(
125	          {
126	            port: +value
127	          },
128	          () => this.props.onGatewayChange(this.isGatewayValid(), this.state)
129	        );
130	        break;
131	      default:
132	      // No default action
133	    }
134	  };
135	
136	  isGatewayValid = (): boolean => {
137	    // gwHostsValid is used as last validation, it's true by default
138	    return this.state.gwHostsValid;
139	  };
140	
141	  onChangeGatewayClass = (gatewayClass: string): void => {
142	    this.setState(
143	      {
144	        gatewayClass: gatewayClass,
145	        isOpen: false
146	      },
147	      () => this.props.onGatewayChange(this.isGatewayValid(), this.state)
148	    );
149	  };
150	
151	  render(): React.ReactNode {
152	    return (
153	      <Form isHorizontal={true}>
154	        <FormGroup label="Add K8s API Gateway" fieldId="gatewaySwitch">
155	          <Switch
156	            id="advanced-gwSwitch"
157	            label={' '}
158	            labelOff={' '}
159	            isChecked={this.state.addGateway}
160	            onChange={() => this.onFormChange(K8sGatewayForm.SWITCH, '')}
161	          />
162	          <span>{wizardTooltip(GATEWAY_TOOLTIP)}</span>
163	        </FormGroup>
164	
165	        {this.state.addGateway && (
166	          <>
167	            <FormGroup fieldId="selectGateway">
168	              <Radio
169	                id="existingGateway"
170	                name="selectGateway"
171	                label="Select K8s API Gateway"
172	                isDisabled={!this.state.addGateway || this.props.k8sGateways.length === 0}
173	                isChecked={!this.state.newGateway}
174	                onChange={() => this.onFormChange(K8sGatewayForm.SELECT, 'false')}
175	              />
176	
177	              <Radio
178	                id="createGateway"
179	                name="selectGateway"
180	                label="Create K8s API Gateway"
181	                isDisabled={!this.state.addGateway}
182	                isChecked={this.state.newGateway}
183	                onChange={() => this.onFormChange(K8sGatewayForm.SELECT, 'true')}
184	              />
185	            </FormGroup>
186	
187	            {!this.state.newGateway && (
188	              <FormGroup fieldId="selectGateway" label="K8sGateway">
189	                {this.props.k8sGateways.length > 0 && (
190	                  <Select
191	                    id="selectGateway"
192	                    isOpen={this.state.isOpen}
193	                    selected={this.state.selectedGateway}
194	                    onSelect={(_event, k8sGateway) =>
195	                      this.onFormChange(K8sGatewayForm.GATEWAY_SELECTED, k8sGateway as string)
196	                    }
197	                    onOpenChange={(isOpen: boolean) => {
198	                      this.setState({ isOpen });
199	                    }}
200	                    toggle={toggleRef =>
201	                      this.toggleMenu(
202	                        toggleRef,
203	                        this.state.selectedGateway,
204	                        !this.state.addGateway || this.state.newGateway || this.props.k8sGateways.length === 0
205	                      )
206	                    }
207	                    shouldFocusToggleOnSelect
208	                  >
209	                    <SelectList>
210	                      {this.props.k8sGateways.map(k8sGateway => (
211	                        <SelectOption key={k8sGateway} value={k8sGateway}>
212	                          {k8sGateway}
213	                        </SelectOption>
214	                      ))}
215	                    </SelectList>
216	                  </Select>
217	                )}
218	                {this.props.k8sGateways.length === 0 && <>There are no K8s API gateways to select.</>}
219	              </FormGroup>
220	            )}
221	
222	            {this.state.newGateway && (
223	              <>
224	                {serverConfig.gatewayAPIClasses.length > 1 && (
225	                  <FormGroup label="Gateway Class" fieldId="gatewayClass">
226	                    <Select
227	                      isOpen={this.state.isOpen}
228	                      selected={this.state.gatewayClass}
229	                      onSelect={(_event, gatewayClass) => this.onChangeGatewayClass(gatewayClass as string)}
230	                      id="gatewayClass"
231	                      onOpenChange={(isOpen: boolean) => {
232	                        this.setState({ isOpen });
233	                      }}
234	                      toggle={toggleRef => this.toggleMenu(toggleRef, this.state.gatewayClass)}
235	                      shouldFocusToggleOnSelect
236	                    >
237	                      <SelectList>
238	                        {serverConfig.gatewayAPIClasses.map((option, index) => (
239	                          <SelectOption key={index} value={option.className}>
240	                            {option.name}
241	                          </SelectOption>
242	                        ))}
243	                      </SelectList>
244	                    </Select>
245	                  </FormGroup>
246	                )}
247	
248	                <FormGroup fieldId="gwPort" label="Port">
249	                  <TextInput
250	                    id="gwPort"
251	                    name="gwPort"
252	                    type="number"
253	                    isDisabled={!this.state.addGateway || !this.state.newGateway}
254	                    value={this.state.port}
255	                    onChange={(_event, value) => this.onFormChange(K8sGatewayForm.PORT, value)}
256	                  />
257	                </FormGroup>
258	
259	                <FormGroup fieldId="gwHosts" label="K8s API Gateway Hosts">
260	                  <TextInput
261	                    id="gwHosts"
262	                    name="gwHosts"
263	                    isDisabled={!this.state.addGateway || !this.state.newGateway}
264	                    value={this.state.gwHosts}
265	                    onChange={(_event, value) => this.onFormChange(K8sGatewayForm.GW_HOSTS, value)}
266	                    validated={isValid(this.state.gwHostsValid)}
267	                  />
268	
269	                  <FormHelperText>
270	                    <HelperText>
271	                      <HelperTextItem>
272	                        {isValid(this.state.gwHostsValid)
273	                          ? 'One or more hosts exposed by this gateway. Enter one or multiple hosts separated by comma'
274	                          : "K8s API Gateway hosts should be specified using FQDN format or '*.' format. IPs are not allowed."}
275	                      </HelperTextItem>
276	                    </HelperText>
277	                  </FormHelperText>
278	                </FormGroup>
279	              </>
280	            )}
281	          </>
282	        )}
283	      </Form>
284	    );
285	  }
286	}

